async (params, browser) => {
  // Open Gmail
  await browser.open('https://mail.google.com/mail/u/0/#inbox')

  // Wait for Gmail to load
  await browser.waitForSelector('[gh=\'cm\'], .T-I.T-I-KE[role=\'button\']', 15000)

  // Let Gmail fully initialize
  await browser.wait(2000)

  // Click compose button
  const open_compose = await browser.evaluate(`const composeBtn = document.querySelector('[gh="cm"]') || document.querySelector('.T-I.T-I-KE[role="button"]'); if (composeBtn) { composeBtn.click(); } else { throw new Error('Compose button not found'); } return { clicked: true }`)

  // Wait for compose window to open
  await browser.wait(2000)

  // Wait for compose form
  await browser.waitForSelector('[aria-label=\'To recipients\'], input[name=\'to\']', 10000)

  // Fill in recipient
  const fill_to = await browser.evaluate(`const toInput = document.querySelector('[aria-label="To recipients"]') || document.querySelector('input[name="to"]') || document.querySelector('textarea[name="to"]'); if (toInput) { toInput.focus(); await new Promise(r => setTimeout(r, 300)); document.execCommand('insertText', false, params.to); toInput.dispatchEvent(new Event('input', { bubbles: true })); await new Promise(r => setTimeout(r, 500)); toInput.dispatchEvent(new KeyboardEvent('keydown', { key: 'Tab', code: 'Tab', keyCode: 9, which: 9, bubbles: true })); } return { to_filled: true }`)

  await browser.wait(500)

  // Fill in subject
  const fill_subject = await browser.evaluate(`const subjectInput = document.querySelector('input[name="subjectbox"]'); if (subjectInput) { subjectInput.focus(); await new Promise(r => setTimeout(r, 300)); document.execCommand('insertText', false, params.subject); subjectInput.dispatchEvent(new Event('input', { bubbles: true })); } return { subject_filled: true }`)

  await browser.wait(500)

  // Fill in message body
  const fill_body = await browser.evaluate(`const bodyDiv = document.querySelector('div[aria-label="Message Body"]') || document.querySelector('.Am.Al.editable'); if (bodyDiv) { bodyDiv.focus(); await new Promise(r => setTimeout(r, 300)); document.execCommand('insertText', false, params.body); bodyDiv.dispatchEvent(new Event('input', { bubbles: true })); } return { body_filled: true }`)

  // Wait before sending
  await browser.wait(1000)

  // Click send
  const result = await browser.evaluate(`const composeBox = document.querySelector('.M9, .AD'); const sendBtn = (composeBox && composeBox.querySelector('[aria-label*="Send"]')) || document.querySelector('.T-I.aoO') || document.querySelector('.dC .T-I[aria-label*="Send"]'); if (sendBtn) { sendBtn.click(); } else { throw new Error('Send button not found'); } return { success: true, message: 'Email sent', to: params.to, subject: params.subject }`)

  // Wait for email to be sent
  await browser.wait(2000)

  return result
}
